const data = $input.first().json;

let resume =
  data.modified_resume ||
  data.output?.modified_resume ||
  data.data?.modified_resume ||
  "";

// Convert tags into HTML colors
resume = resume
  .replace(/\[RED\](.*?)\[\/RED\]/gs,
    '<span style="color:red;font-weight:bold;">$1</span>')

  .replace(/\[YELLOW\](.*?)\[\/YELLOW\]/gs,
    '<span style="color:orange;font-weight:bold;">$1</span>')

  .replace(/\[GREEN\](.*?)\[\/GREEN\]/gs,
    '<span style="color:green;font-weight:bold;">$1</span>');

// Preserve formatting
resume = resume.replace(/\n/g, "<br>");

const html = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
body {
  font-family: Arial, sans-serif;
  padding: 40px;
  line-height: 1.6;
  color: #222;
}
h1,h2,h3 {
  margin-bottom: 10px;
}
</style>
</head>
<body>
${resume}
</body>
</html>
`;

return [
  {
    json: {
      html
    }
  }
];

const data = $input.first().json.data.competition;

function stripHtml(html) {
  return html
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractSection(html, heading) {
  const regex = new RegExp(
    `<strong>${heading}[^<]*<\\/strong>[^<]*<\\/p>\\s*<ul>(.*?)<\\/ul>`,
    'is'
  );
  const match = html.match(regex);
  if (!match) return [];
  const items = [...match[1].matchAll(/<li>(.*?)<\/li>/gis)];
  return items.map(i => stripHtml(i[1]));
}

function parseEligibility(raw) {
  try {
    const e = JSON.parse(raw);
    const result = [];

    if (e.sector?.length) result.push(`Open to: ${e.sector.join(', ')}`);

    const courses = [...(e.engineering || []), ...(e.arts || []), ...(e.others || [])];
    courses.forEach(c => {
      if (typeof c === 'object' && c.course) {
        const spec = c.specialization?.filter(s => s !== 'all').join(', ') || 'all specializations';
        result.push(`${c.course.toUpperCase()} (${spec})`);
      }
    });

    if (e.fresherPassoutYearsSelected?.length) {
      result.push(`Passout year: ${e.fresherPassoutYearsSelected.join(', ')}`);
    }

    return result;
  } catch {
    return [];
  }
}

const details = data.details || '';
const regnReq = data.regnRequirements || {};
const jobDetail = data.job_detail || {};

const result = {
  title: data.title,
  company: data.organisation?.name || null,
  type: data.subtype,
  region: data.region,
  work_type: jobDetail.type,
  timing: jobDetail.timing,
  duration: jobDetail.internship_duration,
  stipend: jobDetail.paid_unpaid,
  openings: jobDetail.openings,
  working_days: jobDetail.working_days,
  apply_by: data.end_date,
  start_date: data.start_date,

  responsibilities: extractSection(details, 'Responsibilities'),
  requirements: extractSection(details, 'Requirements'),
  preferred_skills: extractSection(details, 'Preferred Skills'),
  perks: extractSection(details, 'Perks'),

  skills: (data.skills || []).map(s => s.skill_name),

  eligibility: parseEligibility(regnReq.eligibility),

  perks_structured: (jobDetail.perks || [])
    .filter(p => p.value)
    .map(p => p.text),
};

return [{ json: result }];

const url = $input.first().json.body.jobUrl; // change field name to match your trigger

const match = url.match(/unstop\.com\/o\/([a-zA-Z0-9]+)/);
const shortCode = match ? match[1] : null;

return [{ json: { shortCode } }];

const items = $input.all();

const source = items[0].json.output;
const pdf = items[1].json.data;

return [{
  json: {
    ats_score: source.ats_score,
    ats_level: source.ats_level,
    matched_skills: source.matched_skills,
    missing_skills: source.missing_skills,
    strengths: source.strengths,
    areas_to_improve: source.areas_to_improve,
    recommended_projects: source.recommended_projects,
    pdf_base64: pdf
  }
}];
